// Extract & normalize payload from any BE format (camelCase OR snake_case)
const raw = $input.first().json;
const body = raw.body ?? raw;

const pick = (...vals) => vals.find(v => v !== undefined && v !== null && v !== '') ?? null;

// Extract IDs from any location
const job_id = pick(
  body.job_id, body.jobId,
  body.payload?.job_id, body.payload?.jobId,
  body.payload?.job?.id
);

const project_id = pick(
  body.project_id, body.projectId,
  body.payload?.project_id, body.payload?.projectId,
  body.payload?.project?.id
);

const user_id = pick(
  body.user_id, body.userId,
  body.payload?.user_id, body.payload?.userId,
  body.payload?.user?.id
);

const objective_id = pick(
  body.objective_id, body.objectiveId,
  body.payload?.objective_id, body.payload?.objectiveId,
  body.payload?.objective?.id
);

const diagnosis_id = pick(
  body.diagnosis_id, body.diagnosisId,
  body.payload?.diagnosis_id, body.payload?.diagnosisId,
  body.payload?.diagnosis?.id
);

const input_id = pick(
  body.input_id, body.inputId,
  body.payload?.input_id, body.payload?.inputId
);

// Validate critical IDs
if (!job_id || !project_id || !objective_id) {
  throw new Error(`Missing required IDs. job_id=${job_id}, project_id=${project_id}, objective_id=${objective_id}`);
}

// Extract Define Objective-specific payload
const payload = body.payload ?? body;
const objective_input = pick(
  payload.objective_input,
  payload.objectiveInput,
  body.objective_input,
  body.objectiveInput
) ?? {};

// Business goal (Step 2 sub-step 1)
const business_goal = pick(
  objective_input.business_goal,
  objective_input.businessGoal,
  payload.business_goal,
  payload.businessGoal,
  payload.identify_merged?.business_goal,
  body.business_goal
) ?? {};

// SEO baseline (Step 2 sub-step 2 - auto-prefill from diagnosis)
const seo_baseline = pick(
  objective_input.seo_baseline,
  objective_input.seoBaseline,
  payload.seo_baseline,
  payload.seoBaseline,
  payload.identify_merged?.seo_baseline,
  body.seo_baseline
) ?? {};

// Constraints (Step 2 sub-step 3)
const constraints = pick(
  objective_input.constraints,
  payload.constraints,
  payload.identify_merged?.constraints,
  body.constraints
) ?? {};

// Diagnosis result from Step 1 (for context)
const diagnosis_result = pick(
  objective_input.diagnosis_result,
  objective_input.diagnosisResult,
  payload.diagnosis_result,
  payload.diagnosisResult,
  body.diagnosis_result
) ?? {};

return [{
  json: {
    job_id,
    project_id,
    user_id,
    objective_id,
    diagnosis_id,
    input_id,
    objective_input,
    business_goal,
    seo_baseline,
    constraints,
    diagnosis_result,
    action: pick(body.action, payload.action) ?? 'define_objective'
  }
}];

// DEV MODE: skip HMAC verification
const input = $input.first().json;
return [{ json: { ...input, verified: true } }];

