const raw = typeof query === 'string' ? query : JSON.stringify(query ?? {});
let parsed;
try { parsed = JSON.parse(raw); } catch { parsed = { raw }; }

const diagnosis = parsed.diagnosis_context ?? {};
const baseline = parsed.seo_baseline ?? {};
const constraints = parsed.constraints ?? {};
const achievability = parsed.achievability_hint ?? {};

// Strategy hints per problem type
const strategyHints = {
  technical_bottleneck: 'Focus on fixing crawl/index issues first. Targets: indexed_pages, crawl_errors reduction, CWV.',
  relevance_gap: 'Expand content for commercial keywords. Targets: ranking_keywords count, impressions, qualified_traffic.',
  authority_deficit: 'Build backlinks + digital PR + thought leadership. Targets: DR growth (realistic +8-12 in 6mo), referring_domains.',
  conversion_pitfall: 'Optimize CR via landing pages, CTAs, content quality. Targets: conversion_rate, bounce reduction, session duration.',
  from_scratch: 'Build foundations: GA4/GSC setup, keyword research, content creation, technical SEO. Targets: indexed_pages, initial rankings.',
  mixed: 'Phased approach: tackle most blocking issue first, then layer additional improvements.'
};

return JSON.stringify({
  strategy_hint: strategyHints[diagnosis.primary_problem_type] ?? 'General SEO improvement focus.',
  achievability_calibrated: {
    percent: achievability.percent ?? 50,
    growth_ceiling: achievability.percent >= 70 ? 'aggressive' : achievability.percent >= 50 ? 'moderate' : 'conservative'
  },
  baseline_summary: {
    has_organic_traffic: (baseline.current_monthly_organic_traffic ?? 0) > 0,
    has_rankings: (baseline.current_ranking_keywords ?? 0) > 0,
    has_conversions: (baseline.current_organic_conversions ?? 0) > 0,
    domain_authority: baseline.domain_authority ?? null
  },
  capacity: {
    content_per_month: constraints.content_capacity_per_month ?? null,
    duration: constraints.campaign_duration ?? null,
    competition: constraints.industry_competition_level ?? null
  }
});

// Extract flow data from before AI Agent (because AI Agent overwrites json)
const flow = $('Calculate Achievability1').first().json;
const aiOutput = $input.first().json;

let raw = aiOutput.output ?? aiOutput.text ?? aiOutput.response ?? aiOutput.result ?? aiOutput;
let parsed = raw;

if (typeof raw === 'string') {
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
  try { parsed = JSON.parse(cleaned); } catch { parsed = null; }
}

const VALID_OBJ_TYPES = ['technical_recovery', 'qualified_traffic', 'authority_growth', 'conversion_improvement', 'foundation_building', 'mixed'];
const VALID_ACHIEVE = ['low', 'moderate', 'high'];

if (!parsed || typeof parsed !== 'object') {
  parsed = {
    objective_type: 'mixed',
    smart_objective: 'Objective could not be generated. Please retry.',
    business_goal_alignment: '',
    input_metrics: [],
    output_metrics: [],
    outcome_metrics: [],
    baseline: {},
    target: {},
    time_period: flow.constraints?.campaign_duration ?? '6 months',
    achievability_score: flow.achievability?.score ?? 'moderate',
    achievability_percent: flow.achievability?.percent ?? 50,
    risk_notes: ['AI output was not valid JSON'],
    raw_llm_output: { text: String(raw).slice(0, 2000) },
    model_used: 'gpt-4o-mini'
  };
} else {
  // Enforce enums
  if (!VALID_OBJ_TYPES.includes(parsed.objective_type)) {
    // Auto-map from diagnosis if missing
    const mapping = {
      technical_bottleneck: 'technical_recovery',
      relevance_gap: 'qualified_traffic',
      authority_deficit: 'authority_growth',
      conversion_pitfall: 'conversion_improvement',
      from_scratch: 'foundation_building',
      mixed: 'mixed'
    };
    parsed.objective_type = mapping[flow.diagnosis_result?.primary_problem_type] ?? 'mixed';
  }
  if (!VALID_ACHIEVE.includes(parsed.achievability_score)) {
    parsed.achievability_score = flow.achievability?.score ?? 'moderate';
  }
  if (typeof parsed.achievability_percent !== 'number' || parsed.achievability_percent < 0 || parsed.achievability_percent > 100) {
    parsed.achievability_percent = flow.achievability?.percent ?? 50;
  }
  if (!Array.isArray(parsed.input_metrics)) parsed.input_metrics = [];
  if (!Array.isArray(parsed.output_metrics)) parsed.output_metrics = [];
  if (!Array.isArray(parsed.outcome_metrics)) parsed.outcome_metrics = [];
  if (!Array.isArray(parsed.risk_notes)) parsed.risk_notes = [];
  if (!parsed.baseline || typeof parsed.baseline !== 'object') parsed.baseline = {};
  if (!parsed.target || typeof parsed.target !== 'object') parsed.target = {};
  if (!parsed.smart_objective) parsed.smart_objective = '';
  if (!parsed.business_goal_alignment) parsed.business_goal_alignment = '';
  if (!parsed.time_period) parsed.time_period = flow.constraints?.campaign_duration ?? '6 months';
  if (!parsed.raw_llm_output) parsed.raw_llm_output = {};
  if (!parsed.model_used) parsed.model_used = 'gpt-4o-mini';
}

const now = new Date().toISOString();

return [{
  json: {
    job_id: flow.job_id,
    project_id: flow.project_id,
    user_id: flow.user_id,
    objective_id: flow.objective_id,
    diagnosis_id: flow.diagnosis_id,
    input_id: flow.input_id,
    completed_at: now,
    // Flattened fields for Supabase update
    objective_type: parsed.objective_type,
    smart_objective: parsed.smart_objective,
    business_goal_alignment: parsed.business_goal_alignment,
    input_metrics: parsed.input_metrics,
    output_metrics: parsed.output_metrics,
    outcome_metrics: parsed.outcome_metrics,
    baseline: parsed.baseline,
    target: parsed.target,
    time_period: parsed.time_period,
    achievability_score: parsed.achievability_score,
    achievability_percent: parsed.achievability_percent,
    risk_notes: parsed.risk_notes,
    raw_llm_output: parsed.raw_llm_output,
    model_used: parsed.model_used,
    // Full result for response_payload in jobs table
    objective_result: parsed
  }
}];

// Rule-based Achievability Calculation
// Combines 6 factors into a single 0-100 percentage

const input = $input.first().json;
const constraints = input.constraints ?? {};
const baseline = input.seo_baseline ?? {};
const diagnosis = input.diagnosis_result ?? {};

// Helper: map level to score
const levelScore = (level, map) => map[level] ?? 50;

// 1. Budget capacity (0-100)
const budget_score = levelScore(constraints.budget_level, {
  low: 30, medium: 60, high: 90
});

// 2. Content capacity per month (0-100)
const contentCount = constraints.content_capacity_per_month ?? 4;
const content_score = Math.min(100, contentCount * 10);  // 10 articles/mo = max

// 3. Developer support (binary 0 or 100)
const dev_score = constraints.developer_support_available ? 90 : 40;

// 4. Link building capacity (0-100)
const link_score = levelScore(constraints.link_building_capacity, {
  low: 30, medium: 60, high: 90
});

// 5. Competition level (inverse - higher competition = harder)
const competition_score = levelScore(constraints.industry_competition_level, {
  low: 90, medium: 60, high: 30
});

// 6. Existing brand strength (0-100)
const brand_score = levelScore(constraints.existing_brand_strength, {
  none: 20, low: 40, medium: 65, high: 90
});

// Severity adjustment from diagnosis (lower severity = higher achievability)
const severityAdjust = {
  low: 10, medium: 0, high: -10, critical: -20
};
const severity_bonus = severityAdjust[diagnosis.severity] ?? 0;

// Combined weighted average
const weighted_score = Math.round(
  (budget_score * 0.2 +
   content_score * 0.2 +
   dev_score * 0.1 +
   link_score * 0.15 +
   competition_score * 0.2 +
   brand_score * 0.15) + severity_bonus
);

const achievability_percent = Math.max(0, Math.min(100, weighted_score));

// Map to enum
let achievability_score;
if (achievability_percent < 50) achievability_score = 'low';
else if (achievability_percent <= 70) achievability_score = 'moderate';
else achievability_score = 'high';

return [{
  json: {
    ...input,
    achievability: {
      percent: achievability_percent,
      score: achievability_score,
      breakdown: {
        budget: budget_score,
        content_capacity: content_score,
        developer_support: dev_score,
        link_building: link_score,
        competition: competition_score,
        brand_strength: brand_score,
        severity_bonus
      }
    }
  }
}];

